// Types of the benchmark truth pack (apps/metrics-dashboard/src/bench/truth-pack.json),
// generated by tools/metrics/bench-truth-pack.mjs from the raw archive of the 12 runs.
// Interpretations never live in the pack: it only carries direct measures, reproducible
// derivations and reviewed post-hoc classifications, each with provenance.

export type VariantId = 'flow' | 'friction' | 'overfit'

export type EvidenceLevel = 'direct' | 'derived' | 'reviewable' | 'interpretation'

export type PerVariant<T> = Record<VariantId, T>

export interface S01Run {
  source: string
  status: string
  timeToGreenMs: number
  timeToFirstChangeMs: number
  changedFiles: number
  locAdded: number
  locDeleted: number
  churn: number
  filesInspected: number
  firstRelevantFile: string
  nxAffectedProjects: number | null
}

export interface S02Run {
  source: string
  status: string
  timeToGreenMs: number
  changedFiles: number
  locAdded: number
  locDeleted: number
  churn: number
  changeAmplification: number
  evolutionTax: number
  reopenedS01Files: number
  knowledgeDispersionRaw: number
  duplicatedRiskRulesRaw: number
}

export type RiskRuleMap = Record<string, string[]>

export interface KnowledgeVariant {
  rawAgentMap: RiskRuleMap
  consolidatedMap: RiskRuleMap
  ruleLocationEdges: number
  uniqueFiles: number
  multiRuleFiles: number
  maxRulesPerFile: number
  duplicatedRiskRules: number
  knowledgeDispersionRaw: number
  duplicatedRiskRulesRaw: number
}

export interface KnowledgeMap {
  level: EvidenceLevel
  method: string
  note: string
  excludedGeneratedLocations: string[]
  ruleIds: string[]
  variants: PerVariant<KnowledgeVariant>
}

export interface Consolidated<T> {
  rawReportedValue: T
  consolidatedValue: T | null
  reason: string | null
}

export interface S03Run {
  source: string
  status: string
  timeToRootCauseMs: number
  timeToFirstHypothesisMs: number
  filesInspectedBeforeRootCause: number
  searchesBeforeRootCause: number
  hypothesesBeforeRootCause: number
  falseLeadsBeforeRootCause: number
  rootCauseGroundTruthMatch: boolean
  groundTruthCheckedAfterRootCauseEvent: boolean
  finalBuildPass: Consolidated<boolean | null>
  secondary: {
    timeToBugFixedMs: number
    timeToGreenMs: number
    fixLocAdded: number
    fixLocDeleted: number
    fixChangedFiles: number
    fixStrategy: string
    fixBoundary: string
  }
}

export interface A11yCaps {
  filtersNamed: string
  keyboardSort: string
  ariaSort: boolean
  liveAnnouncement: boolean
  visibleFocus: boolean
  positiveTabindex: number
}

export interface S04Run {
  source: string
  a11y: {
    status: string
    timeToGreenMs: number
    changedFiles: number
    locAdded: number
    locDeleted: number
    churn: number
    measurementMode: string
    axeCriticalBaseline: number
    axeSeriousBaseline: number
    baseline: A11yCaps
    after: A11yCaps
  }
  eco: {
    status: string
    timeToGreenMs: number
    changedFiles: number
    locAdded: number
    locDeleted: number
    churn: number
    measurementMode: string
    baseline: { requestCount: number; apiRequestCount: number; duplicateRequestCount: number }
    after: { requestCount: number; apiRequestCount: number; duplicateRequestCount: number }
    totalTransferReductionPercent: number
    apiTransferReductionPercent: number
  }
  combined: {
    qualityDeliveryCostMs: number
    combinedLocChurn: number
    combinedChangedFileTouches: number
    combinedUniqueChangedFilesCount: number
  }
}

export interface AutoMetrics {
  source: string
  capturedAt: string
  runner: { os: string; node: string }
  coldValidationMs: number
  warmValidationMs: number
  coldSteps: Record<string, number>
  warmSteps: Record<string, number>
  dockerBuild: {
    rawPrimaryImageMs: number
    consolidatedAllReleaseImagesMs: number
    releaseImages: { dockerfile: string | null; durationMs: number }[]
    consolidationReason: string
  }
  dockerImageSizeKb: number
  outsideFactor: { startupMs: number; healthcheckMs: number; note: string }
}

export interface TruthPack {
  $schema: string
  generatedBy: string
  archive: string
  evidenceLevels: EvidenceLevel[]
  protocol: {
    model: string
    reasoningMode: string
    modelCapture: string
    runs: number
    scenarios: number
    codebases: number
    guarantees: string[]
    executionOrders: Record<string, VariantId[]>
    shas: Record<string, PerVariant<{ from: string; to: string }>>
  }
  s01: PerVariant<S01Run>
  s02: PerVariant<S02Run>
  knowledgeMap: KnowledgeMap
  s03: PerVariant<S03Run>
  s04: PerVariant<S04Run>
  cumulative: PerVariant<{ timeMs: number; churn: number; fileTouches: number }>
  autoMetrics: PerVariant<AutoMetrics>
  externalContextSnapshots: {
    metricName: string
    capture: string
    note: string
    values: Record<string, Partial<Record<VariantId, number>>>
    windowTokens: number
  }
}
